def _slow(items):
    result = {}
    for x in items:
        c = 0
        for y in items:
            if x == y:
                c += 1
        if c > 1:
            result[x] = c
    return result
for _case in [['a','b','a','c','b','a','d'], [], [1], [1,1], [1,2,3], [5,5,5,5], ['x','y','x','y','z'], [0,0,1,1,1,2]]:
    assert count_repeats(_case) == _slow(_case), _case
assert count_repeats(['a','b','a','c','b','a','d']) == {'a': 3, 'b': 2}
assert count_repeats([]) == {}
assert count_repeats([1]) == {}
